en(sys.argv) >= 4:\n        mask_arg = sys.argv[3]\n        if mask_arg.startswith(\"0x\"):\n            mask = int(mask_arg, 16)\n        else:\n            mask = int(mask_arg)\n\n    raw = input_path.read_bytes()\n    scrubbed = apply_scrubbing_mask(raw, mask=mask)\n\n    try:\n        inflated = inflate_memory_structure(scrubbed)\n    except zlib.error as e:\n        print(f\"[ERROR] zlib decompression failed: {e}\", file=sys.stderr)\n        sys.exit(2)\n\n    output_path.write_bytes(inflated)\n    print(f\"Wrote inflated memory structure to {output_path}\")\n```\n\n你可以在工作区这样使用它对刚才的片段做一次完整管线测试（默认掩码 0x42）：\n\n```bash\ncd /root/.openclaw/workspace\npython cleaner_tool.py memory_fragment.bin inflated_memory.bin\n```\n\n如果你想把它集成成一个可在 `telemetry_recovery` 包里调用的模块，我可以帮你把导入路径和包装函数整理一下。",
